def process_klines(symbol, data, interval="1h"):
    """Process kline data and calculate rolling statistics"""
    rows = []
    volumes = []
    closes = []
    
    for k in data:
        open_time = datetime.fromtimestamp(k[0] / 1000)
        open_price = float(k[1])
        high_price = float(k[2])
        low_price = float(k[3])
        close_price = float(k[4])
        volume = float(k[5])
        close_time = datetime.fromtimestamp(k[6] / 1000)
        quote_volume = float(k[7])
        trades = int(k[8])
        taker_buy_base = float(k[9])
        taker_buy_quote = float(k[10])
        
        volumes.append(volume)
        closes.append(close_price)
        
        # Calculate rolling statistics (24-period = 24h)
        window = min(24, len(volumes))
        vol_avg_24 = sum(volumes[-window:]) / window if window > 0 else volume
        
        # Price volatility (standard deviation of returns)
        if len(closes) >= 2:
            returns = [(closes[i] - closes[i-1]) / closes[i-1] for i in range(1, len(closes))]
            vol_window = min(24, len(returns))
            if vol_window > 1:
                mean_ret = sum(returns[-vol_window:]) / vol_window
                variance = sum((r - mean_ret) ** 2 for r in returns[-vol_window:]) / vol_window
                volatility = variance ** 0.5
            else:
                volatility = 0
        else:
            volatility = 0
        
        # Price change %
        price_change_pct = ((close_price - open_price) / open_price) * 100 if open_price != 0 else 0
        
        rows.append({
            'timestamp': open_time.strftime('%Y-%m-%d %H:%M:%S'),
            'open': open_price,
            'high': high_price,
            'low': low_price,
            'close': close_price,
            'volume': volume,
            'quote_volume': quote_volume,
            'trades': trades,
            'taker_buy_base': taker_buy_base,
            'taker_buy_quote': taker_buy_quote,
            'price_change_pct': round(price_change_pct, 4),
            'vol_avg_24h': round(vol_avg_24, 4),
            'volatility_24h': round(volatility * 100, 4)  # as percentage
        })
    
    return rows

def save_to_csv(symbol, rows, interval="1h"):
    """Save processed data to CSV"""
    base_dir = Path("/root/.openclaw/workspace/data/binance")
    symbol_dir = base_dir / symbol / interval
    symbol_dir.mkdir(parents=True, exist_ok=True)
    
    # Filename with date range
    first_ts = rows[0]['timestamp'][:10]
    last_ts = rows[-1]['timestamp'][:10]
    filename = f"{symbol}_{interval}_{first_ts}_to_{last_ts}.csv"
    filepath = symbol_dir / filename
    
    fieldnames = ['timestamp', 'open', 'high', 'low', 'close', 'volume', 
                  'quote_volume', 'trades', 'taker_buy_base', 'taker_buy_quote',
                  'price_change_pct', 'vol_avg_24h', 'volatility_24h']
    
    with open(filepath, 'w', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)
    
    return filepath

def generate_summary(symbol, rows):
    """Generate summary statistics"""
    closes = [r['close'] for r in rows]
    volumes = [r['volume'] for r in rows]
    
    return {
        'symbol': symbol,
        'records': len(rows),
        'price_high': max(r['high'] for r in rows),
        'price_low': min(r['low'] for r in rows),
        'price_open': rows[0]['open'],
        'price_close': rows[-1]['close'],
        'price_change_pct': round(((rows[-1]['close'] - rows[0]['open']) / rows[0]['open']) * 100, 4),
        'volume_total': round(sum(volumes), 4),
        'volume_avg': round(sum(volumes) / len(volumes), 4),
        'volatility_max': max(r['volatility_24h'] for r in rows),
        'latest_volatility': rows[-1]['volatility_24h']
    }

def main():
    results = []
    
    # Process each symbol
    symbols_data = [
        ('BTCUSDT', BTC_DATA),
        ('ETHUSDT', ETH_DATA),
        ('SOLUSDT', SOL_DATA)
    ]
    
    for symbol, data in symbols_data:
        print(f"Processing {symbol}...")
        rows = process_klines(symbol, data)
        filepath = save_to_csv(symbol, rows)
        summary = generate_summary(symbol, rows)
        summary['filepath'] = str(filepath)
        results.append(summary)
        print(f"  Saved {len(rows)} records to {filepath}")
    
    # Print summary
    print("\n" + "="*80)
    print("BINANCE KLINE MONITOR - SUMMARY REPORT")
    print("="*80)
    print(f"Run Time: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')} Asia/Shanghai")
    print(f"Data Interval: 1h (last 100 candles ~4 days)")
    print("-"*80)
    
    for r in results:
        print(f"\n{r['symbol']}:")
        print(f"  Records: {r['records']}")
        print(f"  Price Range: ${r['price_low']:,.2f} - ${r['price_high']:,.2f}")
        print(f"  Period Change: {r['price_change_pct']:+.4f}%")
        print(f"  Total Volume: {r['volume_total']:,.4f}")
        print(f"  Avg Volume (per candle): {r['volume_avg']:,.4f}")
        print(f"  Latest Volatility (24h): {r['latest_volatility']:.4f}%")
        print(f"  File: {r['filepath']}")
    
    print("\n" + "="*80)
    print("Archive maintained in: /root/.openclaw/workspace/data/binance/")
    print("="*80)

if __name__ == "__main__":
    main()
